sections.example:
const words = "hello world foo".split(" ");
console.log(words); // ['hello', 'world', 'foo']

const joined = words.join("-");
console.log(joined); // 'hello-world-foo'

// Reverse a string via split/reverse/join
const rev = "abcd".split("").reverse().join("");
console.log(rev); // 'dcba'

